import{_ as t,a,b as d}from"./chunks/配置容量限制.DkdWbdOw.js";import{_ as l,o as i,c as o,a2 as r}from"./chunks/framework.DnrXFDHb.js";const f=JSON.parse('{"title":"افزودن Cloudflare R2 Channel","description":"","frontmatter":{},"headers":[],"relativePath":"fa/upload/cloudflare-r2.md","filePath":"fa/upload/cloudflare-r2.md","lastUpdated":1781962217000}'),n={name:"fa/upload/cloudflare-r2.md"};function c(u,e,h,s,b,p){return i(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="افزودن-cloudflare-r2-channel" tabindex="-1">افزودن Cloudflare R2 Channel <a class="header-anchor" href="#افزودن-cloudflare-r2-channel" aria-label="Permalink to &quot;افزودن Cloudflare R2 Channel&quot;">​</a></h1><h2 id="مناسب-برای-چه-زمانی-است" tabindex="-1">مناسب برای چه زمانی است <a class="header-anchor" href="#مناسب-برای-چه-زمانی-است" aria-label="Permalink to &quot;مناسب برای چه زمانی است&quot;">​</a></h2><p>Cloudflare R2 را زمانی استفاده کنید که:</p><ul><li>ImgBed شما روی Cloudflare deploy شده و می‌خواهید files در R2 bucket همان Cloudflare account ذخیره شوند.</li><li>نمی‌خواهید جداگانه S3 endpoint، access key و secret key تنظیم کنید.</li><li>می‌خواهید read و write با setup کم از طریق Worker یا Pages R2 binding انجام شود.</li></ul><p>خلاصه:</p><p>R2 channel به‌صورت manual داخل ImgBed admin panel ساخته نمی‌شود. ابتدا باید R2 bucket را به Cloudflare project bind کنید و نام binding variable دقیقاً <code>img_r2</code> باشد.</p><h2 id="پیش-از-شروع-چه-چیزهایی-لازم-است" tabindex="-1">پیش از شروع چه چیزهایی لازم است <a class="header-anchor" href="#پیش-از-شروع-چه-چیزهایی-لازم-است" aria-label="Permalink to &quot;پیش از شروع چه چیزهایی لازم است&quot;">​</a></h2><ul><li>Cloudflare account.</li><li>یک R2 bucket موجود.</li><li>permission برای مدیریت Cloudflare project که ImgBed روی آن deploy شده است.</li></ul><h2 id="configure-در-cloudflare" tabindex="-1">Configure در Cloudflare <a class="header-anchor" href="#configure-در-cloudflare" aria-label="Permalink to &quot;Configure در Cloudflare&quot;">​</a></h2><h3 id="_1-ساخت-r2-bucket" tabindex="-1">1. ساخت R2 Bucket <a class="header-anchor" href="#_1-ساخت-r2-bucket" aria-label="Permalink to &quot;1. ساخت R2 Bucket&quot;">​</a></h3><ol><li>وارد Cloudflare Dashboard شوید.</li><li><code>R2 Object Storage</code> را باز کنید.</li><li>Create bucket را بزنید.</li><li>یک bucket name انتخاب کنید، مثل <code>imgbed</code>.</li></ol><p>uploaded files در همین bucket ذخیره می‌شوند.</p><p><img src="'+t+'" alt="Create an R2 bucket" loading="lazy"></p><h3 id="_2-bind-کردن-bucket-به-imgbed-project" tabindex="-1">2. Bind کردن Bucket به ImgBed Project <a class="header-anchor" href="#_2-bind-کردن-bucket-به-imgbed-project" aria-label="Permalink to &quot;2. Bind کردن Bucket به ImgBed Project&quot;">​</a></h3><p>بر اساس deployment type، محل binding را انتخاب کنید:</p><table tabindex="0"><thead><tr><th>Deployment Type</th><th>Binding Location</th></tr></thead><tbody><tr><td>Pages</td><td>Current Pages project -&gt; Settings -&gt; Functions -&gt; R2 bucket bindings</td></tr><tr><td>Worker</td><td>Current Worker -&gt; Settings -&gt; Bindings -&gt; R2 bucket bindings</td></tr></tbody></table><p>هنگام افزودن binding، fields مهم:</p><table tabindex="0"><thead><tr><th>Field</th><th>Value</th></tr></thead><tbody><tr><td>Variable name</td><td><code>img_r2</code></td></tr><tr><td>R2 bucket</td><td>bucket ساخته‌شده را انتخاب کنید.</td></tr></tbody></table><p>Variable name باید دقیقاً <code>img_r2</code> باشد. upload، read و delete فایل‌های R2 به همین binding name وابسته است.</p><h3 id="_3-redeploy-کردن-project" tabindex="-1">3. Redeploy کردن Project <a class="header-anchor" href="#_3-redeploy-کردن-project" aria-label="Permalink to &quot;3. Redeploy کردن Project&quot;">​</a></h3><p>پس از save کردن binding، ImgBed را redeploy کنید تا Worker یا Pages runtime به <code>img_r2</code> دسترسی داشته باشد.</p><h2 id="در-imgbed-چه-می‌بینید" tabindex="-1">در ImgBed چه می‌بینید <a class="header-anchor" href="#در-imgbed-چه-می‌بینید" aria-label="Permalink to &quot;در ImgBed چه می‌بینید&quot;">​</a></h2><p>بعد از آماده شدن R2 binding، باز کنید:</p><ol><li>System Settings.</li><li>Upload Settings.</li><li>channel با نام <code>Cloudflare R2</code>.</li></ol><p>system به‌صورت خودکار یک fixed channel می‌سازد:</p><table tabindex="0"><thead><tr><th>Field</th><th>Fixed Value</th></tr></thead><tbody><tr><td>Channel name</td><td><code>Cloudflare R2</code></td></tr><tr><td>Channel type</td><td><code>cfr2</code></td></tr><tr><td>Storage mode</td><td><code>binding</code></td></tr><tr><td>Configuration source</td><td>Environment binding</td></tr></tbody></table><p>این fixed binding channel است. لازم نیست برای ساخت آن Add Channel بزنید و مانند channel معمولی قابل delete نیست.</p><h2 id="fields-قابل-ویرایش-در-admin-panel" tabindex="-1">Fields قابل ویرایش در Admin Panel <a class="header-anchor" href="#fields-قابل-ویرایش-در-admin-panel" aria-label="Permalink to &quot;Fields قابل ویرایش در Admin Panel&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Field</th><th>کاربرد</th><th>Required</th></tr></thead><tbody><tr><td>Enable channel</td><td>مشخص می‌کند R2 در upload selection شرکت کند یا نه.</td><td>Yes</td></tr><tr><td>Account ID</td><td>فقط وقتی quota limits enabled است و official R2 usage query لازم است.</td><td>Recommended when quota limits are enabled</td></tr><tr><td>Bucket name</td><td>فقط وقتی quota limits enabled است و official R2 usage query لازم است.</td><td>Recommended when quota limits are enabled</td></tr><tr><td>Quota limit</td><td>مشخص می‌کند این R2 channel بر اساس capacity در upload selection شرکت کند یا نه.</td><td>No</td></tr><tr><td>Threshold</td><td>وقتی usage به درصد مشخصی رسید، نوشتن روی این channel متوقف می‌شود.</td><td>Required when quota limits are enabled</td></tr></tbody></table><p>Account ID را از account information panel در Cloudflare dashboard copy کنید. فقط اگر می‌خواهید ImgBed R2 quota usage را query و enforce کند، آن را وارد کنید.</p><p><img src="'+a+'" alt="Get the Account ID" loading="lazy"></p><h2 id="مراحل-setup" tabindex="-1">مراحل setup <a class="header-anchor" href="#مراحل-setup" aria-label="Permalink to &quot;مراحل setup&quot;">​</a></h2><ol><li>در Cloudflare یک R2 bucket بسازید.</li><li>Cloudflare settings مربوط به ImgBed project را باز کنید.</li><li>R2 bucket binding اضافه کنید.</li><li><code>Variable name</code> را <code>img_r2</code> بگذارید.</li><li>R2 bucket ساخته‌شده را انتخاب کنید.</li><li>binding را save کنید و ImgBed را redeploy کنید.</li><li>به ImgBed -&gt; System Settings -&gt; Upload Settings برگردید.</li><li>بررسی کنید <code>Cloudflare R2</code> channel دیده می‌شود و enabled است.</li></ol><p>اگر می‌خواهید R2 بر اساس capacity در upload selection شرکت کند، quota limit را enable کنید و سپس Account ID، bucket name، quota limit و threshold را وارد و save کنید.</p><p><img src="'+d+'" alt="Configure quota limits" loading="lazy"></p><h2 id="روش-بررسی" tabindex="-1">روش بررسی <a class="header-anchor" href="#روش-بررسی" aria-label="Permalink to &quot;روش بررسی&quot;">​</a></h2><ul><li>fixed <code>Cloudflare R2</code> channel در Upload Settings دیده شود.</li><li>channel card نشان دهد enabled است.</li><li>یک test file کوچک upload شود و returned link باز شود.</li><li>اگر هنگام باز کردن file پیام <code>R2 database binding is not configured</code> دیدید، runtime binding <code>img_r2</code> را دریافت نکرده است. binding name را در Cloudflare بررسی کنید و project را redeploy کنید.</li></ul>',37)])])}const k=l(n,[["render",c]]);export{f as __pageData,k as default};
